/* Auto-generated stubs for trampoline branch targets */
#include "ppu_recomp.h"
#include <stdio.h>

static void stub_log(const char* name, ppu_context* ctx) {
    static int s_count = 0;
    s_count++;
    if (s_count <= 100 || s_count % 500 == 0) {
        fprintf(stderr, "[STUB] %s called #%d SP=0x%08X LR=0x%08X r3=0x%llX\n",
                name, s_count, (uint32_t)ctx->gpr[1], (uint32_t)ctx->lr,
                (unsigned long long)ctx->gpr[3]);
        fflush(stderr);
    }
}
#define STUB_FUNC(name) void name(ppu_context* ctx) { stub_log(#name, ctx); }

